static const asmkit_arm_thumb2_td_bucket_range_t* arm_thumb2_td_bucket(uint32_t word)
{
    uint32_t key;
    size_t lo;
    size_t hi;
    key = word & ASMKIT_ARM_THUMB2_TD_BUCKET_MASK;
    lo = 0u;
    hi = ASMKIT_ARRAY_COUNT(asmkit_arm_thumb2_td_buckets);
    while (lo < hi) {
        size_t mid = lo + ((hi - lo) >> 1);
        const asmkit_arm_thumb2_td_bucket_range_t* bucket = &asmkit_arm_thumb2_td_buckets[mid];
        if (bucket->key < key) {
            lo = mid + 1u;
        } else {
            hi = mid;
        }
    }
    if (lo < ASMKIT_ARRAY_COUNT(asmkit_arm_thumb2_td_buckets) && asmkit_arm_thumb2_td_buckets[lo].key == key) {
        return &asmkit_arm_thumb2_td_buckets[lo];
    }
    return 0;
}

static const asmkit_arm_thumb2_td_bucket_range_t* arm_thumb2_td_fallback_bucket(uint32_t word)
{
    uint32_t key;
    size_t lo;
    size_t hi;
    key = word & ASMKIT_ARM_THUMB2_TD_FALLBACK_BUCKET_MASK;
    lo = 0u;
    hi = ASMKIT_ARRAY_COUNT(asmkit_arm_thumb2_td_fallback_buckets);
    while (lo < hi) {
        size_t mid = lo + ((hi - lo) >> 1);
        const asmkit_arm_thumb2_td_bucket_range_t* bucket = &asmkit_arm_thumb2_td_fallback_buckets[mid];
        if (bucket->key < key) {
            lo = mid + 1u;
        } else {
            hi = mid;
        }
    }
    if (lo < ASMKIT_ARRAY_COUNT(asmkit_arm_thumb2_td_fallback_buckets) && asmkit_arm_thumb2_td_fallback_buckets[lo].key == key) {
        return &asmkit_arm_thumb2_td_fallback_buckets[lo];
    }
    return 0;
}

static const asmkit_arm_thumb2_td_bucket_range_t* arm_thumb2_td_subbucket(uint32_t word, const asmkit_arm_thumb2_td_subbucket_desc_t* desc)
{
    uint32_t key;
    uint32_t lo;
    uint32_t hi;
    if (desc->mask == 0u || desc->count == 0u) {
        return 0;
    }
    key = word & desc->mask;
    lo = desc->first;
    hi = desc->first + desc->count;
    while (lo < hi) {
        uint32_t mid = lo + ((hi - lo) >> 1);
        const asmkit_arm_thumb2_td_bucket_range_t* bucket = &asmkit_arm_thumb2_td_subbuckets[mid];
        if (bucket->key < key) {
            lo = mid + 1u;
        } else {
            hi = mid;
        }
    }
    if (lo < desc->first + desc->count && asmkit_arm_thumb2_td_subbuckets[lo].key == key) {
        return &asmkit_arm_thumb2_td_subbuckets[lo];
    }
    return 0;
}

static int64_t arm_sign_extend(uint32_t value, unsigned bits)
{
    uint32_t sign;
    sign = (uint32_t)1u << (bits - 1u);
    return (int64_t)(value ^ sign) - (int64_t)sign;
}

static asmkit_mnemonic_id_t arm_mnemonic_id(uint32_t id)
{
    switch (id) {
    case ASMKIT_ARM_OTHER:
        return ASMKIT_GEN_ARM_MNEMONIC_OTHER_ID;
    case ASMKIT_ARM_B:
    case ASMKIT_THUMB_B:
    case ASMKIT_THUMB_B_COND:
        return ASMKIT_GEN_ARM_MNEMONIC_B_ID;
    case ASMKIT_ARM_BL:
    case ASMKIT_THUMB_BL:
        return ASMKIT_GEN_ARM_MNEMONIC_BL_ID;
    case ASMKIT_ARM_BX:
    case ASMKIT_THUMB_BX:
        return ASMKIT_GEN_ARM_MNEMONIC_BX_ID;
    case ASMKIT_ARM_BLX:
    case ASMKIT_THUMB_BLX:
        return ASMKIT_GEN_ARM_MNEMONIC_BLX_ID;
    case ASMKIT_ARM_LDR_LITERAL:
        return ASMKIT_GEN_ARM_MNEMONIC_LDR_ID;
    case ASMKIT_THUMB_IT:
        return ASMKIT_GEN_ARM_MNEMONIC_IT_ID;
    default:
        return ASMKIT_MNEMONIC_INVALID;
    }
}

static uint32_t arm_td_bit_width(uint32_t value)
{
    uint32_t width;
    width = 0u;
    while (value != 0u) {
        ++width;
        value >>= 1;
    }
    return width;
}

static uint32_t arm_td_ror32(uint32_t value, uint8_t rotate)
{
    rotate = (uint8_t)(rotate & 31u);
    return rotate == 0u ? value : (uint32_t)((value >> rotate) | (value << (32u - rotate)));
}

static uint32_t arm_td_t2_so_imm(uint32_t value)
{
    uint32_t imm8;
    value &= 0x0fffu;
    imm8 = value & 0xffu;
    if ((value & 0xc00u) == 0u) {
        switch ((value >> 8u) & 3u) {
        case 0u:
            return imm8;
        case 1u:
            return (imm8 << 16u) | imm8;
        case 2u:
            return (imm8 << 24u) | (imm8 << 8u);
        default:
            return (imm8 << 24u) | (imm8 << 16u) | (imm8 << 8u) | imm8;
        }
    }
    return arm_td_ror32(0x80u | (value & 0x7fu), (uint8_t)((value >> 7u) & 31u));
}

static int arm_td_register_info_matches_class(const asmkit_register_info_t* info, uint8_t reg_class, uint16_t expected_width)
{
    if (info == 0) {
        return 0;
    }
    if (expected_width != 0u && info->width != 0u && info->width != expected_width) {
        return 0;
    }
    switch (reg_class) {
    case ASMKIT_ARM_REGCLASS_GPR:
        return info->id >= ASMKIT_ARM_REG_R0 && info->id <= ASMKIT_ARM_REG_PC;
    case ASMKIT_ARM_REGCLASS_SPR:
        return info->width == 32u && info->parent_id >= ASMKIT_ARM_REG_D0 && info->parent_id <= ASMKIT_ARM_REG_D15;
    case ASMKIT_ARM_REGCLASS_DPR:
        return info->width == 64u && info->parent_id >= ASMKIT_ARM_REG_Q0 && info->parent_id <= ASMKIT_ARM_REG_Q15;
    case ASMKIT_ARM_REGCLASS_QPR:
        return info->id >= ASMKIT_ARM_REG_Q0 && info->id <= ASMKIT_ARM_REG_Q15;
    case ASMKIT_ARM_REGCLASS_VCCR:
        return info->id == ASMKIT_ARM_REG_P0;
    default:
        return 0;
    }
}

static uint32_t arm_td_reg_id(uint32_t encoding, uint16_t width, uint8_t reg_class)
{
    uint32_t i;
    if (reg_class == ASMKIT_ARM_REGCLASS_GPR && width == 32u && encoding <= 15u) {
        return ASMKIT_ARM_REG_R0 + encoding;
    }
    if (reg_class == ASMKIT_ARM_REGCLASS_DPR && encoding <= 31u) {
        return ASMKIT_ARM_REG_D0 + encoding;
    }
    if (reg_class == ASMKIT_ARM_REGCLASS_QPR && encoding <= 15u) {
        return ASMKIT_ARM_REG_Q0 + encoding;
    }
    for (i = 0u; i < ASMKIT_ARM_REGISTER_COUNT; ++i) {
        const asmkit_register_info_t* info = asmkit_gen_arm_register_info_by_index(i);
        if (info != 0 && info->encoding == encoding && arm_td_register_info_matches_class(info, reg_class, width)) {
            return info->id;
        }
    }
    return ASMKIT_ARM_REG_INVALID;
}

static asmkit_operand_t arm_td_tgpr_operand(uint32_t value, const asmkit_arm_td_operand_desc_t* desc, uint32_t odd)
{
    uint32_t encoded;
    uint32_t reg;
    encoded = value & desc->source_mask;
    if ((desc->source_mask & 1u) == 0u) {
        encoded |= odd;
    }
    if ((encoded & 1u) != odd) {
        return asmkit_operand_none();
    }
    if (odd != 0u && encoded > 11u) {
        return asmkit_operand_none();
    }
    if (odd == 0u && encoded > 14u) {
        return asmkit_operand_none();
    }
    reg = arm_td_reg_id(encoded, 32u, ASMKIT_ARM_REGCLASS_GPR);
    if (reg == ASMKIT_ARM_REG_INVALID) {
        return asmkit_operand_none();
    }
    return asmkit_operand_reg(reg, 32u);
}

static asmkit_operand_t arm_td_reg_list_operand(uint32_t value, const asmkit_arm_td_operand_desc_t* desc)
{
    asmkit_operand_t operand;
    if (desc->reg_class == ASMKIT_ARM_REGCLASS_DPR || desc->reg_class == ASMKIT_ARM_REGCLASS_SPR) {
        uint32_t start = (value >> 8u) & 0x1fu;
        uint32_t count = value & 0xffu;
        uint32_t reg;
        if (desc->reg_class == ASMKIT_ARM_REGCLASS_DPR) {
            if ((count & 1u) != 0u) {
                return asmkit_operand_none();
            }
            count >>= 1u;
        }
        if (count == 0u || count > 32u || start + count > 32u) {
            return asmkit_operand_none();
        }
        reg = arm_td_reg_id(start, desc->width, desc->reg_class);
        if (reg == ASMKIT_ARM_REG_INVALID) {
            return asmkit_operand_none();
        }
        operand = asmkit_operand_reg(reg, desc->width);
        operand.flags |= ASMKIT_OPERAND_FLAG_VECTOR_LIST;
        operand.imm = (int64_t)(count | (1u << 8));
        return operand;
    }
    operand = asmkit_operand_reg((uint64_t)(value & desc->source_mask), desc->width);
    operand.flags |= ASMKIT_OPERAND_FLAG_REGISTER_LIST;
    return operand;
}

static uint32_t arm_td_vec_list_shape(uint8_t transform)
{
    switch (transform) {
    case ASMKIT_ARM_TD_TRANSFORM_VEC_LIST_2:
        return 2u | (1u << 8);
    case ASMKIT_ARM_TD_TRANSFORM_VEC_LIST_3:
        return 3u | (1u << 8);
    case ASMKIT_ARM_TD_TRANSFORM_VEC_LIST_4:
        return 4u | (1u << 8);
    case ASMKIT_ARM_TD_TRANSFORM_VEC_LIST_2_SPACED:
        return 2u | (2u << 8);
    default:
        return 1u | (1u << 8);
    }
}

static asmkit_operand_t arm_td_vec_list_operand(uint32_t value, const asmkit_arm_td_operand_desc_t* desc)
{
    uint32_t reg;
    uint32_t encoded;
    asmkit_operand_t operand;
    encoded = value & desc->source_mask;
    if (desc->reg_class == ASMKIT_ARM_REGCLASS_QPR && desc->source_mask == 0x1fu) {
        if ((encoded & 1u) != 0u) {
            return asmkit_operand_none();
        }
        encoded >>= 1u;
    }
    reg = arm_td_reg_id(encoded, desc->width, desc->reg_class);
    if (reg == ASMKIT_ARM_REG_INVALID) {
        return asmkit_operand_none();
    }
    operand = asmkit_operand_reg(reg, desc->width);
    operand.flags |= ASMKIT_OPERAND_FLAG_VECTOR_LIST;
    operand.imm = (int64_t)arm_td_vec_list_shape(desc->transform);
    return operand;
}

static asmkit_operand_t arm_td_mem_base_operand(uint32_t value, const asmkit_arm_td_operand_desc_t* desc)
{
    uint32_t base;
    if (desc->transform != ASMKIT_ARM_TD_TRANSFORM_MEM_BASE || (desc->source_mask != 0x07u && desc->source_mask != 0x0fu)) {
        return asmkit_operand_none();
    }
    base = arm_td_reg_id(value & desc->source_mask, 32u, ASMKIT_ARM_REGCLASS_GPR);
    if (base == ASMKIT_ARM_REG_INVALID) {
        return asmkit_operand_none();
    }
    {
        asmkit_operand_t operand = asmkit_operand_mem(base, 0, desc->width);
        operand.mem.address_width = 32u;
        return operand;
    }
}

static asmkit_operand_t arm_td_mem_base_disp_operand(uint32_t value, uint16_t width, uint32_t scale, uint32_t imm_shift, uint32_t base_shift, uint32_t base_mask, uint32_t imm_mask, uint32_t sign_bit, uint32_t positive_sign_value)
{
    uint32_t base;
    int64_t disp;
    base = arm_td_reg_id((value >> base_shift) & base_mask, 32u, ASMKIT_ARM_REGCLASS_GPR);
    if (base == ASMKIT_ARM_REG_INVALID) {
        return asmkit_operand_none();
    }
    disp = (int64_t)(((value & imm_mask) >> imm_shift) * scale);
    if (sign_bit != 0u && (((value & sign_bit) != 0u) != (positive_sign_value != 0u))) {
        disp = -disp;
    }
    {
        asmkit_operand_t operand = asmkit_operand_mem(base, disp, width);
        operand.mem.address_width = 32u;
        return operand;
    }
}

static asmkit_operand_t arm_td_mem_fixed_base_disp_operand(uint32_t base, uint32_t value, uint16_t width, uint32_t scale, uint32_t imm_mask)
{
    asmkit_operand_t operand = asmkit_operand_mem(base, (int64_t)((value & imm_mask) * scale), width);
    operand.mem.address_width = 32u;
    return operand;
}

static asmkit_operand_t arm_td_mem_thumb_rr_operand(uint32_t value, uint16_t width)
{
    uint32_t base;
    uint32_t index;
    base = arm_td_reg_id(value & 7u, 32u, ASMKIT_ARM_REGCLASS_GPR);
    index = arm_td_reg_id((value >> 3u) & 7u, 32u, ASMKIT_ARM_REGCLASS_GPR);
    if (base == ASMKIT_ARM_REG_INVALID || index == ASMKIT_ARM_REG_INVALID) {
        return asmkit_operand_none();
    }
    {
        asmkit_operand_t operand = asmkit_operand_mem_full(base, index, 1u, 0, width, 32u);
        return operand;
    }
}

static asmkit_operand_t arm_td_mem_t2_so_reg_operand(uint32_t value, uint16_t width)
{
    static const uint8_t scales[4] = {1u, 2u, 4u, 8u};
    uint32_t base;
    uint32_t index;
    base = arm_td_reg_id((value >> 6u) & 0x0fu, 32u, ASMKIT_ARM_REGCLASS_GPR);
    index = arm_td_reg_id((value >> 2u) & 0x0fu, 32u, ASMKIT_ARM_REGCLASS_GPR);
    if (base == ASMKIT_ARM_REG_INVALID || index == ASMKIT_ARM_REG_INVALID) {
        return asmkit_operand_none();
    }
    {
        asmkit_operand_t operand = asmkit_operand_mem_full(base, index, scales[value & 3u], 0, width, 32u);
        return operand;
    }
}

static uint32_t arm_td_arm_alignment_bytes(uint32_t code)
{
    switch (code & 3u) {
    case 1u: return 8u;
    case 2u: return 16u;
    case 3u: return 32u;
    default: return 0u;
    }
}

static asmkit_operand_t arm_td_mem_neon_addrmode6_operand(uint32_t value, const asmkit_arm_td_operand_desc_t* desc)
{
    uint32_t base;
    asmkit_operand_t operand;
    value &= desc->source_mask;
    base = arm_td_reg_id(value & 0x0fu, 32u, ASMKIT_ARM_REGCLASS_GPR);
    if (base == ASMKIT_ARM_REG_INVALID) {
        return asmkit_operand_none();
    }
    operand = asmkit_operand_mem(base, 0, desc->width);
    operand.mem.address_width = 32u;
    operand.imm = (int64_t)arm_td_arm_alignment_bytes(value >> 4u);
    return operand;
}

static asmkit_operand_t arm_td_mem_neon_am6offset_operand(uint32_t value, const asmkit_arm_td_operand_desc_t* desc)
{
    uint32_t index;
    asmkit_operand_t operand;
    index = arm_td_reg_id(value & desc->source_mask, 32u, ASMKIT_ARM_REGCLASS_GPR);
    if (index == ASMKIT_ARM_REG_INVALID) {
        return asmkit_operand_none();
    }
    operand = asmkit_operand_none();
    operand.kind = ASMKIT_OP_MEM;
    operand.mem.index = index;
    operand.mem.scale = 1u;
    operand.mem.address_width = 32u;
    operand.width = desc->width;
    return operand;
}

static uint32_t arm_td_mve_mem_disp_scale(const asmkit_arm_td_operand_desc_t* desc)
{
    if (desc->width == 64u) { return 8u; }
    if (desc->width == 32u) { return 4u; }
    if (desc->width == 16u) { return 2u; }
    return 1u;
}

static asmkit_operand_t arm_td_mem_mve_addr_operand(uint32_t value, const asmkit_arm_td_operand_desc_t* desc)
{
    uint32_t base;
    uint32_t index;
    uint32_t imm;
    int64_t disp;
    value &= desc->source_mask;
    if (desc->source_mask == 0x7fu) {
        index = arm_td_reg_id(value & 0x07u, 32u, ASMKIT_ARM_REGCLASS_GPR);
        base = arm_td_reg_id((value >> 3u) & 0x0fu, 32u, ASMKIT_ARM_REGCLASS_GPR);
        if (base == ASMKIT_ARM_REG_INVALID || index == ASMKIT_ARM_REG_INVALID) {
            return asmkit_operand_none();
        }
        return asmkit_operand_mem_full(base, index, 1u, 0, desc->width, 32u);
    }
    imm = value & 0xffu;
    disp = (int64_t)(imm & 0x7fu);
    if ((imm & 0x80u) == 0u) {
        disp = -disp;
    }
    disp *= (int64_t)arm_td_mve_mem_disp_scale(desc);
    if (desc->source_mask == 0xffu) {
        asmkit_operand_t operand = asmkit_operand_mem(0u, disp, desc->width);
        operand.mem.address_width = 32u;
        return operand;
    }
    base = arm_td_reg_id((value >> 8u) & (desc->source_mask == 0x7ffu ? 0x07u : 0x0fu), 32u, ASMKIT_ARM_REGCLASS_GPR);
    if (base == ASMKIT_ARM_REG_INVALID) {
        return asmkit_operand_none();
    }
    {
        asmkit_operand_t operand = asmkit_operand_mem(base, disp, desc->width);
        operand.mem.address_width = 32u;
        return operand;
    }
}

static asmkit_operand_t arm_td_mem_mve_addr_q_operand(uint32_t value, const asmkit_arm_td_operand_desc_t* desc)
{
    uint32_t base;
    uint32_t index;
    value &= desc->source_mask;
    if (desc->source_mask != 0x7fu) {
        return asmkit_operand_none();
    }
    index = arm_td_reg_id(value & 0x07u, 128u, ASMKIT_ARM_REGCLASS_QPR);
    base = arm_td_reg_id((value >> 3u) & 0x0fu, 32u, ASMKIT_ARM_REGCLASS_GPR);
    if (base == ASMKIT_ARM_REG_INVALID || index == ASMKIT_ARM_REG_INVALID) {
        return asmkit_operand_none();
    }
    return asmkit_operand_mem_full(base, index, 1u, 0, desc->width, 32u);
}

static asmkit_operand_t arm_td_mem_mve_addr_qi_operand(uint32_t value, const asmkit_arm_td_operand_desc_t* desc)
{
    uint32_t base;
    uint32_t imm;
    int64_t disp;
    value &= desc->source_mask;
    if (desc->source_mask != 0x7ffu && desc->source_mask != 0xfffu) {
        return asmkit_operand_none();
    }
    imm = value & 0xffu;
    disp = (int64_t)(imm & 0x7fu);
    if ((imm & 0x80u) == 0u) {
        disp = -disp;
    }
    disp *= (int64_t)arm_td_mve_mem_disp_scale(desc);
    base = arm_td_reg_id((value >> 8u) & 0x07u, 128u, ASMKIT_ARM_REGCLASS_QPR);
    if (base == ASMKIT_ARM_REG_INVALID) {
        return asmkit_operand_none();
    }
    {
        asmkit_operand_t operand = asmkit_operand_mem(base, disp, desc->width);
        operand.mem.address_width = 128u;
        return operand;
    }
}

static asmkit_operand_t arm_td_mem_tbb_operand(uint32_t value, uint16_t width, uint8_t scale)
{
    uint32_t base;
    uint32_t index;
    base = arm_td_reg_id((value >> 4u) & 0x0fu, 32u, ASMKIT_ARM_REGCLASS_GPR);
    index = arm_td_reg_id(value & 0x0fu, 32u, ASMKIT_ARM_REGCLASS_GPR);
    if (base == ASMKIT_ARM_REG_INVALID || index == ASMKIT_ARM_REG_INVALID) {
        return asmkit_operand_none();
    }
    return asmkit_operand_mem_full(base, index, scale, 0, width, 32u);
}

static asmkit_operand_t arm_td_mem_thumb_pc_operand(uint32_t value, uint16_t width)
{
    asmkit_operand_t operand = asmkit_operand_mem(ASMKIT_ARM_REG_PC, (int64_t)((value & 0xffu) * 4u), width);
    operand.mem.address_width = 32u;
    return operand;
}

static asmkit_operand_t arm_td_mem_arm_addrmode3_operand(uint32_t value, uint16_t width)
{
    uint32_t base;
    uint32_t positive;
    base = arm_td_reg_id((value >> 9u) & 0x0fu, 32u, ASMKIT_ARM_REGCLASS_GPR);
    if (base == ASMKIT_ARM_REG_INVALID) {
        return asmkit_operand_none();
    }
    positive = value & 0x100u;
    if ((value & 0x2000u) != 0u) {
        int64_t disp = (int64_t)((value & 0x0fu) | (value & 0xf0u));
        asmkit_operand_t operand;
        if (positive == 0u) {
            disp = -disp;
        }
        operand = asmkit_operand_mem(base, disp, width);
        operand.mem.address_width = 32u;
        return operand;
    }
    {
        uint32_t index = arm_td_reg_id(value & 0x0fu, 32u, ASMKIT_ARM_REGCLASS_GPR);
        asmkit_operand_t operand;
        if (index == ASMKIT_ARM_REG_INVALID) {
            return asmkit_operand_none();
        }
        operand = asmkit_operand_mem_full(base, index, 1u, 0, width, 32u);
        if (positive == 0u) {
            operand.flags |= ASMKIT_OPERAND_FLAG_ARM_NEGATIVE_OFFSET;
        }
        return operand;
    }
}

static int arm_td_apply_arm_mem_shift(asmkit_operand_t* operand, uint32_t value)
{
    uint8_t shift_type = (uint8_t)((value >> 5u) & 3u);
    uint8_t amount = (uint8_t)((value >> 7u) & 31u);
    if (shift_type == 1u && amount == 0u) {
        amount = 32u;
    } else if (shift_type == 2u && amount == 0u) {
        amount = 32u;
    } else if (shift_type == 3u && amount == 0u) {
        operand->shift_kind = 4u;
        operand->shift_amount = 0u;
        return 1;
    }
    operand->shift_kind = shift_type;
    operand->shift_amount = amount;
    return 1;
}

static asmkit_operand_t arm_td_mem_arm_ldst_so_reg_operand(uint32_t value, uint16_t width)
{
    uint32_t base;
    uint32_t index;
    asmkit_operand_t operand;
    base = arm_td_reg_id((value >> 13u) & 0x0fu, 32u, ASMKIT_ARM_REGCLASS_GPR);
    index = arm_td_reg_id(value & 0x0fu, 32u, ASMKIT_ARM_REGCLASS_GPR);
    if (base == ASMKIT_ARM_REG_INVALID || index == ASMKIT_ARM_REG_INVALID) {
        return asmkit_operand_none();
    }
    operand = asmkit_operand_mem_full(base, index, 1u, 0, width, 32u);
    if ((value & 0x1000u) == 0u) {
        operand.flags |= ASMKIT_OPERAND_FLAG_ARM_NEGATIVE_OFFSET;
    }
    if (!arm_td_apply_arm_mem_shift(&operand, value)) {
        return asmkit_operand_none();
    }
    return operand;
}

static asmkit_operand_t arm_td_mem_arm_am2offset_reg_operand(uint32_t value, uint16_t width)
{
    uint32_t index;
    asmkit_operand_t operand;
    index = arm_td_reg_id(value & 0x0fu, 32u, ASMKIT_ARM_REGCLASS_GPR);
    if (index == ASMKIT_ARM_REG_INVALID) {
        return asmkit_operand_none();
    }
    operand = asmkit_operand_none();
    operand.kind = ASMKIT_OP_MEM;
    operand.mem.index = index;
    operand.mem.scale = 1u;
    operand.mem.address_width = 32u;
    operand.width = width;
    if ((value & 0x1000u) == 0u) {
        operand.flags |= ASMKIT_OPERAND_FLAG_ARM_NEGATIVE_OFFSET;
    }
    if (!arm_td_apply_arm_mem_shift(&operand, value)) {
        return asmkit_operand_none();
    }
    return operand;
}

static asmkit_operand_t arm_td_mem_arm_am3offset_operand(uint32_t value, uint16_t width)
{
    uint32_t positive = value & 0x100u;
    asmkit_operand_t operand;
    if ((value & 0x200u) != 0u) {
        int64_t disp = (int64_t)((value & 0x0fu) | (value & 0xf0u));
        if (positive == 0u) {
            disp = -disp;
        }
        operand = asmkit_operand_none();
        operand.kind = ASMKIT_OP_MEM;
        operand.mem.displacement = disp;
        operand.mem.scale = 1u;
        operand.mem.address_width = 32u;
        operand.width = width;
        return operand;
    }
    {
        uint32_t index = arm_td_reg_id(value & 0x0fu, 32u, ASMKIT_ARM_REGCLASS_GPR);
        if (index == ASMKIT_ARM_REG_INVALID) {
            return asmkit_operand_none();
        }
        operand = asmkit_operand_none();
        operand.kind = ASMKIT_OP_MEM;
        operand.mem.index = index;
        operand.mem.scale = 1u;
        operand.mem.address_width = 32u;
        operand.width = width;
        if (positive == 0u) {
            operand.flags |= ASMKIT_OPERAND_FLAG_ARM_NEGATIVE_OFFSET;
        }
        return operand;
    }
}

static asmkit_operand_t arm_td_mem_operand(uint32_t value, const asmkit_arm_td_operand_desc_t* desc)
{
    switch (desc->transform) {
    case ASMKIT_ARM_TD_TRANSFORM_MEM_BASE:
        return arm_td_mem_base_operand(value, desc);
    case ASMKIT_ARM_TD_TRANSFORM_MEM_ARM_IMM12:
        return arm_td_mem_base_disp_operand(value, desc->width, 1u, 0u, 13u, 0x0fu, 0xfffu, 0x1000u, 1u);
    case ASMKIT_ARM_TD_TRANSFORM_MEM_ARM_ADDRMODE5:
        return arm_td_mem_base_disp_operand(value, desc->width, 4u, 0u, 9u, 0x0fu, 0xffu, 0x100u, 1u);
    case ASMKIT_ARM_TD_TRANSFORM_MEM_THUMB_IMM1:
        return arm_td_mem_base_disp_operand(value, desc->width, 1u, 3u, 0u, 0x07u, 0xf8u, 0u, 0u);
    case ASMKIT_ARM_TD_TRANSFORM_MEM_THUMB_IMM2:
        return arm_td_mem_base_disp_operand(value, desc->width, 2u, 3u, 0u, 0x07u, 0xf8u, 0u, 0u);
    case ASMKIT_ARM_TD_TRANSFORM_MEM_THUMB_IMM4:
        return arm_td_mem_base_disp_operand(value, desc->width, 4u, 3u, 0u, 0x07u, 0xf8u, 0u, 0u);
    case ASMKIT_ARM_TD_TRANSFORM_MEM_THUMB_SP:
        return arm_td_mem_fixed_base_disp_operand(ASMKIT_ARM_REG_SP, value, desc->width, 4u, 0xffu);
    case ASMKIT_ARM_TD_TRANSFORM_MEM_THUMB_PC:
        return arm_td_mem_thumb_pc_operand(value, desc->width);
    case ASMKIT_ARM_TD_TRANSFORM_MEM_THUMB_RR:
        return arm_td_mem_thumb_rr_operand(value, desc->width);
    case ASMKIT_ARM_TD_TRANSFORM_MEM_T2_SO_REG:
        return arm_td_mem_t2_so_reg_operand(value, desc->width);
    case ASMKIT_ARM_TD_TRANSFORM_MEM_T2_IMM12:
        return arm_td_mem_base_disp_operand(value, desc->width, 1u, 0u, 13u, 0x0fu, 0xfffu, 0u, 0u);
    case ASMKIT_ARM_TD_TRANSFORM_MEM_T2_POSIMM8:
        return arm_td_mem_base_disp_operand(value, desc->width, 1u, 0u, 9u, 0x0fu, 0xffu, 0u, 0u);
    case ASMKIT_ARM_TD_TRANSFORM_MEM_T2_NEGIMM8:
        if ((desc->source_mask & 0x100u) == 0u) {
            return arm_td_mem_base_disp_operand(value, desc->width, 1u, 0u, 9u, 0x0fu, 0xffu, 0x100u, 0u);
        }
        return arm_td_mem_base_disp_operand(value, desc->width, 1u, 0u, 9u, 0x0fu, 0xffu, 0x100u, 1u);
    case ASMKIT_ARM_TD_TRANSFORM_MEM_T2_FORCE_NEGIMM8:
        return arm_td_mem_base_disp_operand(value | 0x100u, desc->width, 1u, 0u, 9u, 0x0fu, 0xffu, 0x100u, 0u);
    case ASMKIT_ARM_TD_TRANSFORM_MEM_T2_IMM8S4:
        return arm_td_mem_base_disp_operand(value, desc->width, 4u, 0u, 9u, 0x0fu, 0xffu, 0x100u, 1u);
    case ASMKIT_ARM_TD_TRANSFORM_MEM_T2_IMM7S4:
        return arm_td_mem_base_disp_operand(value, desc->width, 4u, 0u, 8u, 0x0fu, 0x7fu, 0x80u, 1u);
    case ASMKIT_ARM_TD_TRANSFORM_MEM_T2_IMM0_1020S4:
        return arm_td_mem_base_disp_operand(value, desc->width, 4u, 0u, 8u, 0x0fu, 0xffu, 0u, 0u);
    case ASMKIT_ARM_TD_TRANSFORM_MEM_ARM_ADDRMODE3:
        return arm_td_mem_arm_addrmode3_operand(value, desc->width);
    case ASMKIT_ARM_TD_TRANSFORM_MEM_ARM_LDST_SO_REG:
        return arm_td_mem_arm_ldst_so_reg_operand(value, desc->width);
    case ASMKIT_ARM_TD_TRANSFORM_MEM_ARM_AM2OFFSET_REG:
        return arm_td_mem_arm_am2offset_reg_operand(value, desc->width);
    case ASMKIT_ARM_TD_TRANSFORM_MEM_ARM_AM3OFFSET:
        return arm_td_mem_arm_am3offset_operand(value, desc->width);
    case ASMKIT_ARM_TD_TRANSFORM_MEM_NEON_ADDRMODE6:
        return arm_td_mem_neon_addrmode6_operand(value, desc);
    case ASMKIT_ARM_TD_TRANSFORM_MEM_NEON_AM6OFFSET:
        return arm_td_mem_neon_am6offset_operand(value, desc);
    case ASMKIT_ARM_TD_TRANSFORM_MEM_MVE_ADDR:
        return arm_td_mem_mve_addr_operand(value, desc);
    case ASMKIT_ARM_TD_TRANSFORM_MEM_MVE_ADDR_Q:
        return arm_td_mem_mve_addr_q_operand(value, desc);
    case ASMKIT_ARM_TD_TRANSFORM_MEM_MVE_ADDR_QI:
        return arm_td_mem_mve_addr_qi_operand(value, desc);
    case ASMKIT_ARM_TD_TRANSFORM_MEM_TBB:
        return arm_td_mem_tbb_operand(value, desc->width, 1u);
    case ASMKIT_ARM_TD_TRANSFORM_MEM_TBH:
        return arm_td_mem_tbb_operand(value, desc->width, 2u);
    default:
        return asmkit_operand_none();
    }
}

static asmkit_operand_t arm_td_shifted_reg_imm_operand(uint32_t value, uint16_t width)
{
    uint32_t reg;
    uint8_t shift_type;
    uint8_t amount;
    asmkit_operand_t operand;
    reg = arm_td_reg_id(value & 0x0fu, width == 0u ? 32u : width, ASMKIT_ARM_REGCLASS_GPR);
    if (reg == ASMKIT_ARM_REG_INVALID) {
        return asmkit_operand_none();
    }
    shift_type = (uint8_t)((value >> 5u) & 3u);
    amount = (uint8_t)((value >> 7u) & 31u);
    operand = asmkit_operand_reg(reg, width == 0u ? 32u : width);
    if (shift_type == 1u && amount == 0u) {
        amount = 32u;
    } else if (shift_type == 2u && amount == 0u) {
        amount = 32u;
    } else if (shift_type == 3u && amount == 0u) {
        operand.shift_kind = 4u;
        return operand;
    }
    operand.shift_kind = shift_type;
    operand.shift_amount = amount;
    return operand;
}

static asmkit_operand_t arm_td_shifted_reg_reg_operand(uint32_t value, uint16_t width)
{
    uint32_t reg;
    uint32_t shift_reg;
    asmkit_operand_t operand;
    reg = arm_td_reg_id(value & 0x0fu, width == 0u ? 32u : width, ASMKIT_ARM_REGCLASS_GPR);
    shift_reg = arm_td_reg_id((value >> 8u) & 0x0fu, 32u, ASMKIT_ARM_REGCLASS_GPR);
    if (reg == ASMKIT_ARM_REG_INVALID || shift_reg == ASMKIT_ARM_REG_INVALID) {
        return asmkit_operand_none();
    }
    operand = asmkit_operand_reg(reg, width == 0u ? 32u : width);
    operand.shift_kind = (uint8_t)((value >> 5u) & 3u);
    operand.shift_reg = shift_reg;
    return operand;
}

static asmkit_operand_t arm_td_postidx_reg_operand(uint32_t value, uint16_t width)
{
    uint32_t reg;
    asmkit_operand_t operand;
    reg = arm_td_reg_id(value & 0x0fu, 32u, ASMKIT_ARM_REGCLASS_GPR);
    if (reg == ASMKIT_ARM_REG_INVALID) {
        return asmkit_operand_none();
    }
    operand = asmkit_operand_reg(reg, width == 0u ? 32u : width);
    if ((value & 0x10u) == 0u) {
        operand.flags |= ASMKIT_OPERAND_FLAG_ARM_NEGATIVE_OFFSET;
    }
    return operand;
}

static int arm_td_operand_reg_encoding(const asmkit_operand_t* operand, uint8_t reg_class, uint16_t width, uint32_t* out_value)
{
    const asmkit_register_info_t* info;
    if (operand->kind != ASMKIT_OP_REG) {
        return 0;
    }
    if (operand->shift_kind != 0u || operand->shift_amount != 0u || operand->shift_reg != 0u ||
        operand->extend_kind != 0u || operand->extend_amount != 0u ||
        (operand->flags & (ASMKIT_OPERAND_FLAG_REGISTER_LIST | ASMKIT_OPERAND_FLAG_AARCH64_EXTENDED_REG)) != 0u) {
        return 0;
    }
    info = asmkit_gen_arm_register_info((uint32_t)operand->reg);
    if (info != 0 && info->encoding <= 31u &&
        arm_td_register_info_matches_class(info, reg_class, width) &&
        (width == 0u || operand->width == 0u || operand->width == width || info->width == 0u)) {
        *out_value = (uint32_t)info->encoding;
        return 1;
    }
    if (reg_class == ASMKIT_ARM_REGCLASS_GPR && operand->reg <= 15u && (width == 0u || operand->width == 0u || operand->width == width)) {
        *out_value = (uint32_t)operand->reg;
        return 1;
    }
    return 0;
}

static asmkit_operand_t arm_td_derived_reg_operand(const asmkit_operand_t* base_operand, const asmkit_arm_td_operand_desc_t* desc)
{
    uint32_t base;
    uint32_t reg;
    uint32_t reg_id;
    if (!arm_td_operand_reg_encoding(base_operand, desc->reg_class, desc->width, &base)) {
        return asmkit_operand_none();
    }
    reg = base + desc->source_mask;
    if (desc->reg_class == ASMKIT_ARM_REGCLASS_DPR && desc->width == 64u) {
        reg &= 31u;
    } else if (reg > 31u) {
        return asmkit_operand_none();
    }
    reg_id = arm_td_reg_id(reg, desc->width, desc->reg_class);
    if (reg_id == ASMKIT_ARM_REG_INVALID) {
        return asmkit_operand_none();
    }
    return asmkit_operand_reg(reg_id, desc->width);
}

static asmkit_operand_t arm_td_fixed_reg_operand(uint32_t reg_id, const asmkit_arm_td_operand_desc_t* desc)
{
    return asmkit_operand_reg(reg_id, desc->width == 0u ? 32u : desc->width);
}

static int64_t arm_td_imm_value(uint32_t value, const asmkit_arm_td_operand_desc_t* desc)
{
    uint32_t bits;
    value &= desc->source_mask;
    if (desc->transform == ASMKIT_ARM_TD_TRANSFORM_MOD_IMM) {
        return (int64_t)arm_td_ror32(value & 0xffu, (uint8_t)(((value >> 8u) & 0x0fu) * 2u));
    }
    if (desc->transform == ASMKIT_ARM_TD_TRANSFORM_T2_SO_IMM) {
        return (int64_t)arm_td_t2_so_imm(value);
    }
    if (desc->transform == ASMKIT_ARM_TD_TRANSFORM_RAW_SIGNED) {
        bits = arm_td_bit_width(desc->source_mask);
        return bits == 0u ? 0 : arm_sign_extend(value, bits);
    }
    if (desc->transform == ASMKIT_ARM_TD_TRANSFORM_NEON_VCVT_IMM32) {
        return (int64_t)(64u - value);
    }
    if (desc->transform == ASMKIT_ARM_TD_TRANSFORM_VEC_SHIFT_RIGHT) {
        uint32_t lane_width = UINT32_C(1) << arm_td_bit_width(desc->source_mask);
        if (desc->source_mask == 0u || lane_width < 8u || lane_width > 64u || value > lane_width) {
            return 0;
        }
        return (int64_t)(lane_width - value);
    }
    if (desc->transform == ASMKIT_ARM_TD_TRANSFORM_IMM_FIXED_LITERAL) {
        return (int64_t)desc->source_mask;
    }
    if (desc->transform == ASMKIT_ARM_TD_TRANSFORM_IMM_PLUS_ONE) {
        return (int64_t)value + 1;
    }
    if (desc->transform == ASMKIT_ARM_TD_TRANSFORM_POSTIDX_IMM8) {
        int64_t disp = (int64_t)(value & 0xffu);
        return (value & 0x100u) != 0u ? disp : -disp;
    }
    if (desc->transform == ASMKIT_ARM_TD_TRANSFORM_POSTIDX_IMM8S4) {
        int64_t disp = (int64_t)(value & 0xffu) * 4;
        return (value & 0x100u) != 0u ? disp : -disp;
    }
    if (desc->transform == ASMKIT_ARM_TD_TRANSFORM_IMM_SCALE4) {
        return (int64_t)value * 4;
    }
    if (desc->transform == ASMKIT_ARM_TD_TRANSFORM_AM2OFFSET_IMM) {
        int64_t disp = (int64_t)(value & 0xfffu);
        return (value & 0x1000u) != 0u ? disp : -disp;
    }
    if (desc->transform == ASMKIT_ARM_TD_TRANSFORM_MVE_SATURATE_OP) {
        return (value & 1u) != 0u ? 48 : 64;
    }
    if (desc->transform == ASMKIT_ARM_TD_TRANSFORM_COMPLEX_ROTATE) {
        return (int64_t)value * 90;
    }
    if (desc->transform == ASMKIT_ARM_TD_TRANSFORM_COMPLEX_ROTATE_ODD) {
        return (value & 1u) != 0u ? 270 : 90;
    }
    return (int64_t)value;
}

static asmkit_operand_t arm_td_pc_rel_operand(uint64_t address, uint32_t value, const asmkit_arm_td_operand_desc_t* desc)
{
    asmkit_operand_t operand;
    uint64_t base;
    uint32_t width;
    int64_t disp;
    base = address;
    width = arm_td_bit_width(desc->source_mask);
    if (width == 0u) {
        return asmkit_operand_none();
    }
    value &= desc->source_mask;
    switch (desc->transform) {
    case ASMKIT_ARM_TD_TRANSFORM_PC_REL_A32_WORDS4:
        disp = (arm_sign_extend(value, width) << 2) + 8;
        break;
    case ASMKIT_ARM_TD_TRANSFORM_PC_REL_A32_WORDS2:
        disp = (arm_sign_extend(value, width) << 1) + 8;
        break;
    case ASMKIT_ARM_TD_TRANSFORM_PC_REL_THUMB_WORDS2:
        disp = (arm_sign_extend(value, width) << 1) + 4;
        break;
    case ASMKIT_ARM_TD_TRANSFORM_PC_REL_THUMB_CB:
        disp = ((int64_t)value << 1) + 4;
        break;
    case ASMKIT_ARM_TD_TRANSFORM_PC_REL_ARM_ADR:
    {
        uint32_t imm;
        if (desc->source_mask != 0x3fffu) {
            return asmkit_operand_none();
        }
        imm = arm_td_ror32(value & 0xffu, (uint8_t)(((value >> 8u) & 0x0fu) * 2u));
        if ((value & 0x1000u) != 0u) {
            disp = 8 - (int64_t)imm;
        } else if ((value & 0x2000u) != 0u) {
            disp = 8 + (int64_t)imm;
        } else {
            return asmkit_operand_none();
        }
        break;
    }
    case ASMKIT_ARM_TD_TRANSFORM_PC_REL_THUMB_ADR:
        base = (address + 4u) & ~UINT64_C(3);
        disp = (int64_t)(value & 0xffu) << 2;
        break;
    case ASMKIT_ARM_TD_TRANSFORM_PC_REL_T2_ADR:
        base = (address + 4u) & ~UINT64_C(3);
        if ((value & 0x1000u) != 0u) {
            value &= 0x0fffu;
            if (value == 0u) {
                return asmkit_operand_none();
            }
            disp = -(int64_t)value;
        } else {
            disp = (int64_t)(value & 0x0fffu);
        }
        break;
    case ASMKIT_ARM_TD_TRANSFORM_PC_REL_THUMB_T2_B:
    {
        uint32_t i_bit;
        uint32_t j1_bit;
        uint32_t j2_bit;
        if (desc->source_mask != 0x00ffffffu && desc->source_mask != 0x00fffffeu) {
            return asmkit_operand_none();
        }
        i_bit = value & 0x00800000u;
        j1_bit = ((i_bit != 0u) ^ ((value & 0x00400000u) == 0u)) ? 0x00400000u : 0u;
        j2_bit = ((i_bit != 0u) ^ ((value & 0x00200000u) == 0u)) ? 0x00200000u : 0u;
        value = (value & ~0x00600000u) | j1_bit | j2_bit;
        disp = (arm_sign_extend(value, 24u) << 1) + 4;
        break;
    }
    case ASMKIT_ARM_TD_TRANSFORM_PC_REL_THUMB_T2_BLX:
    {
        uint32_t i_bit;
        uint32_t j1_bit;
        uint32_t j2_bit;
        if (desc->source_mask != 0x00ffffffu && desc->source_mask != 0x00fffffeu) {
            return asmkit_operand_none();
        }
        base = (address + 4u) & ~UINT64_C(3);
        i_bit = value & 0x00800000u;
        j1_bit = ((i_bit != 0u) ^ ((value & 0x00400000u) == 0u)) ? 0x00400000u : 0u;
        j2_bit = ((i_bit != 0u) ^ ((value & 0x00200000u) == 0u)) ? 0x00200000u : 0u;
        value = (value & ~0x00600000u) | j1_bit | j2_bit;
        disp = arm_sign_extend(value, 24u) << 1;
        break;
    }
    case ASMKIT_ARM_TD_TRANSFORM_PC_REL_THUMB_T2_BCC:
        if (desc->source_mask != 0x001ffffeu) {
            return asmkit_operand_none();
        }
        disp = arm_sign_extend(value, 21u) + 4;
        break;
    case ASMKIT_ARM_TD_TRANSFORM_PC_REL_T2_LDR_LABEL:
        if (desc->source_mask != 0x00001fffu) {
            return asmkit_operand_none();
        }
        base = (address + 4u) & ~UINT64_C(3);
        if ((value & 0x1000u) != 0u) {
            disp = (int64_t)(value & 0x0fffu);
        } else {
            value &= 0x0fffu;
            if (value == 0u) {
                return asmkit_operand_none();
            }
            disp = -(int64_t)value;
        }
        break;
    default:
        return asmkit_operand_none();
    }
    operand = asmkit_operand_pc_rel(disp, desc->width != 0u ? desc->width : (uint16_t)width);
    operand.abs_target = base + (uint64_t)disp;
    return operand;
}

static int arm_td_decoded_operands_valid(const asmkit_arm_td_record_t* record, const asmkit_inst_t* inst)
{
    uint8_t i;
    switch (record->id) {
    case ASMKIT_ARM_TDINST_MVE_VPTv16i8r:
    case ASMKIT_ARM_TDINST_MVE_VPTv16s8r:
    case ASMKIT_ARM_TDINST_MVE_VPTv16u8r:
    case ASMKIT_ARM_TDINST_MVE_VPTv4f32r:
    case ASMKIT_ARM_TDINST_MVE_VPTv4i32r:
    case ASMKIT_ARM_TDINST_MVE_VPTv4s32r:
    case ASMKIT_ARM_TDINST_MVE_VPTv4u32r:
    case ASMKIT_ARM_TDINST_MVE_VPTv8f16r:
    case ASMKIT_ARM_TDINST_MVE_VPTv8i16r:
    case ASMKIT_ARM_TDINST_MVE_VPTv8s16r:
    case ASMKIT_ARM_TDINST_MVE_VPTv8u16r:
        for (i = 0u; i < inst->operand_count; ++i) {
            if (inst->operands[i].kind == ASMKIT_OP_REG && inst->operands[i].width == 32u && inst->operands[i].reg == ASMKIT_ARM_REG_PC) {
                return 0;
            }
        }
        break;
    default:
        break;
    }
    return 1;
}

static int arm_decode_td_operands(const asmkit_arm_td_record_t* record, uint32_t word, uint64_t address, asmkit_inst_t* out_inst)
{
    uint32_t seen[ASMKIT_MAX_OPERANDS];
    uint32_t values[ASMKIT_MAX_OPERANDS];
    uint32_t i;
    if (record->operand_count > ASMKIT_MAX_OPERANDS) {
        return 0;
    }
    if (record->operand_count == 0u) {
        return 1;
    }
    for (i = 0u; i < ASMKIT_MAX_OPERANDS; ++i) {
        seen[i] = 0u;
        values[i] = 0u;
    }
    for (i = 0u; i < record->piece_count; ++i) {
        const asmkit_arm_td_piece_t* piece = &asmkit_arm_td_pieces[record->piece_index + i];
        if (piece->operand_index < ASMKIT_MAX_OPERANDS && piece->src_bit < 32u) {
            uint32_t bit = (word >> piece->dst_bit) & 1u;
            uint32_t mask = UINT32_C(1) << piece->src_bit;
            if ((seen[piece->operand_index] & mask) != 0u && (((values[piece->operand_index] >> piece->src_bit) & 1u) != bit)) {
                return 0;
            }
            seen[piece->operand_index] |= mask;
            values[piece->operand_index] = (values[piece->operand_index] & ~mask) | (bit << piece->src_bit);
        }
    }
    for (i = 0u; i < record->operand_count; ++i) {
        const asmkit_arm_td_operand_desc_t* desc = &asmkit_arm_td_operand_descs[record->operand_desc_index + i];
        asmkit_operand_t operand = asmkit_operand_none();
        uint32_t value;
        if (desc->operand_index >= ASMKIT_MAX_OPERANDS) {
            return 0;
        }
        if (desc->transform == ASMKIT_ARM_TD_TRANSFORM_REG_MEM_BASE_ALIAS ||
            desc->transform == ASMKIT_ARM_TD_TRANSFORM_REG_DERIVED ||
            desc->transform == ASMKIT_ARM_TD_TRANSFORM_REG_FIXED_SP ||
            desc->transform == ASMKIT_ARM_TD_TRANSFORM_REG_FIXED_LR ||
            desc->transform == ASMKIT_ARM_TD_TRANSFORM_REG_FIXED_LITERAL) {
            continue;
        }
        value = values[desc->operand_index];
        if (desc->kind == ASMKIT_ARM_TD_OPERAND_REG) {
            if (desc->transform == ASMKIT_ARM_TD_TRANSFORM_SHIFTED_REG_IMM) {
                operand = arm_td_shifted_reg_imm_operand(value & desc->source_mask, desc->width);
            } else if (desc->transform == ASMKIT_ARM_TD_TRANSFORM_SHIFTED_REG_REG) {
                operand = arm_td_shifted_reg_reg_operand(value & desc->source_mask, desc->width);
            } else if (desc->transform == ASMKIT_ARM_TD_TRANSFORM_REG_LIST) {
                operand = arm_td_reg_list_operand(value, desc);
            } else if (desc->transform >= ASMKIT_ARM_TD_TRANSFORM_VEC_LIST_1 && desc->transform <= ASMKIT_ARM_TD_TRANSFORM_VEC_LIST_2_SPACED) {
                operand = arm_td_vec_list_operand(value, desc);
            } else if (desc->transform == ASMKIT_ARM_TD_TRANSFORM_REG_POSTIDX) {
                operand = arm_td_postidx_reg_operand(value & desc->source_mask, desc->width);
            } else if (desc->transform == ASMKIT_ARM_TD_TRANSFORM_REG_QPR_FROM_DREG) {
                uint32_t encoded = value & desc->source_mask;
                uint32_t reg;
                if ((encoded & 1u) != 0u) {
                    return 0;
                }
                reg = arm_td_reg_id(encoded >> 1u, desc->width, desc->reg_class);
                if (reg == ASMKIT_ARM_REG_INVALID) {
                    return 0;
                }
                operand = asmkit_operand_reg(reg, desc->width);
            } else if (desc->transform == ASMKIT_ARM_TD_TRANSFORM_REG_TGPR_EVEN) {
                operand = arm_td_tgpr_operand(value, desc, 0u);
            } else if (desc->transform == ASMKIT_ARM_TD_TRANSFORM_REG_TGPR_ODD) {
                operand = arm_td_tgpr_operand(value, desc, 1u);
            } else {
                uint32_t reg = arm_td_reg_id(value & desc->source_mask, desc->width, desc->reg_class);
                if (reg == ASMKIT_ARM_REG_INVALID) {
                    return 0;
                }
                operand = asmkit_operand_reg(reg, desc->width);
            }
            if (operand.kind == ASMKIT_OP_NONE) {
                return 0;
            }
        } else if (desc->kind == ASMKIT_ARM_TD_OPERAND_IMM) {
            if (desc->transform == ASMKIT_ARM_TD_TRANSFORM_BF_INV_MASK_WIDTH) {
                uint32_t lsb;
                uint32_t msb;
                if (desc->alias_base_index >= ASMKIT_MAX_OPERANDS) {
                    return 0;
                }
                lsb = values[desc->alias_base_index] & 0x1fu;
                msb = (value & desc->source_mask) >> 5u;
                if (msb < lsb) {
                    return 0;
                }
                operand = asmkit_operand_imm((int64_t)(msb - lsb + 1u), desc->width);
            } else {
                operand = asmkit_operand_imm(arm_td_imm_value(value, desc), desc->width);
            }
        } else if (desc->kind == ASMKIT_ARM_TD_OPERAND_MEM) {
            operand = arm_td_mem_operand(value, desc);
        } else if (desc->kind == ASMKIT_ARM_TD_OPERAND_PC_REL) {
            operand = arm_td_pc_rel_operand(address, value, desc);
        } else {
            return 0;
        }
        if (operand.kind == ASMKIT_OP_NONE) {
            return 0;
        }
        operand.operand_index = desc->operand_index;
        out_inst->operands[desc->operand_index] = operand;
    }
    for (i = 0u; i < record->operand_count; ++i) {
        const asmkit_arm_td_operand_desc_t* desc = &asmkit_arm_td_operand_descs[record->operand_desc_index + i];
        const asmkit_operand_t* base_operand;
        asmkit_operand_t operand;
        if (desc->operand_index >= ASMKIT_MAX_OPERANDS) {
            return 0;
        }
        if (desc->transform == ASMKIT_ARM_TD_TRANSFORM_REG_MEM_BASE_ALIAS) {
            if (desc->alias_base_index >= ASMKIT_MAX_OPERANDS) {
                return 0;
            }
            base_operand = &out_inst->operands[desc->alias_base_index];
            if (base_operand->kind != ASMKIT_OP_MEM || base_operand->mem.base == 0u) {
                return 0;
            }
            operand = asmkit_operand_reg(base_operand->mem.base, desc->width == 0u ? 32u : desc->width);
        } else if (desc->transform == ASMKIT_ARM_TD_TRANSFORM_REG_DERIVED) {
            if (desc->alias_base_index >= ASMKIT_MAX_OPERANDS) {
                return 0;
            }
            base_operand = &out_inst->operands[desc->alias_base_index];
            operand = arm_td_derived_reg_operand(base_operand, desc);
            if (operand.kind == ASMKIT_OP_NONE) {
                return 0;
            }
        } else if (desc->transform == ASMKIT_ARM_TD_TRANSFORM_REG_FIXED_SP) {
            operand = arm_td_fixed_reg_operand(ASMKIT_ARM_REG_SP, desc);
        } else if (desc->transform == ASMKIT_ARM_TD_TRANSFORM_REG_FIXED_LR) {
            operand = arm_td_fixed_reg_operand(ASMKIT_ARM_REG_LR, desc);
        } else if (desc->transform == ASMKIT_ARM_TD_TRANSFORM_REG_FIXED_LITERAL) {
            operand = arm_td_fixed_reg_operand(desc->source_mask, desc);
        } else {
            continue;
        }
        operand.operand_index = desc->operand_index;
        out_inst->operands[desc->operand_index] = operand;
    }
    out_inst->operand_count = record->operand_count;
    return arm_td_decoded_operands_valid(record, out_inst);
}

static int arm_td_features_match(const asmkit_engine_t* engine, const asmkit_arm_td_record_t* record)
{
    uint32_t word;
    for (word = 0u; word < ASMKIT_FEATURE_WORD_COUNT; ++word) {
        uint64_t required = record->feature_bits[word];
        if ((required & ~asmkit_engine_feature_word(engine, word)) != 0u) {
            return 0;
        }
    }
    return 1;
}

static int arm_td_record_decodes_operands(const asmkit_arm_td_record_t* record, uint32_t word)
{
    asmkit_inst_t scratch;
    asmkit_zero(&scratch, sizeof(scratch));
    return arm_decode_td_operands(record, word, 0u, &scratch);
}

static int arm_td_space_matches(uint8_t record_space, uint8_t requested_space)
{
    if (requested_space == ASMKIT_ARM_TD_SPACE_ANY) {
        return 1;
    }
    if (requested_space == ASMKIT_ARM_TD_SPACE_PRIMARY) {
        return record_space != ASMKIT_ARM_TD_SPACE_THUMB2_COPROC && record_space != ASMKIT_ARM_TD_SPACE_THUMB2_CDE;
    }
    return record_space == requested_space;
}

static void arm_consider_td_record(
    const asmkit_engine_t* engine,
    uint32_t word,
    uint8_t decode_space,
    int check_features,
    const asmkit_arm_td_record_t* record,
    uint32_t record_index,
    const asmkit_arm_td_record_t** best_record,
    uint32_t* best_index,
    uint8_t* best_priority,
    uint8_t* best_fixed_bits,
    int* have_best,
    uint32_t* best_blocked_index,
    uint8_t* best_blocked_priority,
    uint8_t* best_blocked_fixed_bits,
    int* have_blocked)
{
    if (!arm_td_space_matches(record->decode_space, decode_space)) {
        return;
    }
    if ((word & record->mask) != record->value) {
        return;
    }
    if (!arm_td_record_decodes_operands(record, word)) {
        return;
    }
    if (check_features && !arm_td_features_match(engine, record)) {
        if (!*have_blocked || record->priority > *best_blocked_priority ||
            (record->priority == *best_blocked_priority && record->fixed_bits > *best_blocked_fixed_bits) ||
            (record->priority == *best_blocked_priority && record->fixed_bits == *best_blocked_fixed_bits && record_index < *best_blocked_index)) {
            *best_blocked_index = record_index;
            *best_blocked_priority = record->priority;
            *best_blocked_fixed_bits = record->fixed_bits;
            *have_blocked = 1;
        }
        return;
    }
    if (!*have_best || record->priority > *best_priority ||
        (record->priority == *best_priority && record->fixed_bits > *best_fixed_bits) ||
        (record->priority == *best_priority && record->fixed_bits == *best_fixed_bits && record_index < *best_index)) {
        *best_record = record;
        *best_index = record_index;
        *best_priority = record->priority;
        *best_fixed_bits = record->fixed_bits;
        *have_best = 1;
    }
}

static void arm_consider_arm_a32_td_indexed_bucket(
    const asmkit_engine_t* engine,
    uint32_t word,
    uint8_t decode_space,
    int check_features,
    const asmkit_arm_td_record_t* records,
    const asmkit_arm_a32_td_subbucket_desc_t* subdesc,
    const uint32_t* base_indices,
    uint32_t first,
    uint32_t count,
    const asmkit_arm_td_record_t** best_record,
    uint32_t* best_index,
    uint8_t* best_priority,
    uint8_t* best_fixed_bits,
    int* have_best,
    uint32_t* best_blocked_index,
    uint8_t* best_blocked_priority,
    uint8_t* best_blocked_fixed_bits,
    int* have_blocked)
{
    const asmkit_arm_a32_td_bucket_range_t* subbucket;
    uint32_t end;
    uint32_t i;
    if (subdesc->mask != 0u) {
        subbucket = arm_a32_td_subbucket(word, subdesc);
        if (subbucket != 0) {
            end = subbucket->first + subbucket->count;
            for (i = subbucket->first; i < end; ++i) {
                uint32_t record_index = asmkit_arm_a32_td_subbucket_indices[i];
                const asmkit_arm_td_record_t* record = &records[record_index];
                arm_consider_td_record(engine, word, decode_space, check_features, record, record_index, best_record, best_index, best_priority, best_fixed_bits, have_best, best_blocked_index, best_blocked_priority, best_blocked_fixed_bits, have_blocked);
            }
        }
        end = subdesc->fallback_first + subdesc->fallback_count;
        for (i = subdesc->fallback_first; i < end; ++i) {
            uint32_t record_index = asmkit_arm_a32_td_subbucket_fallback_indices[i];
            const asmkit_arm_td_record_t* record = &records[record_index];
            arm_consider_td_record(engine, word, decode_space, check_features, record, record_index, best_record, best_index, best_priority, best_fixed_bits, have_best, best_blocked_index, best_blocked_priority, best_blocked_fixed_bits, have_blocked);
        }
        return;
    }
    end = first + count;
    for (i = first; i < end; ++i) {
        uint32_t record_index = base_indices[i];
        const asmkit_arm_td_record_t* record = &records[record_index];
        arm_consider_td_record(engine, word, decode_space, check_features, record, record_index, best_record, best_index, best_priority, best_fixed_bits, have_best, best_blocked_index, best_blocked_priority, best_blocked_fixed_bits, have_blocked);
    }
}

