static const asmkit_arm_td_record_t* arm_find_a32_td_record_in_space(const asmkit_engine_t* engine, uint32_t word, uint8_t decode_space, int check_features)
{
    const asmkit_arm_a32_td_bucket_range_t* bucket;
    const asmkit_arm_td_record_t* best_record = 0;
    uint32_t best_index = (uint32_t)~0u;
    uint8_t best_priority = 0u;
    uint8_t best_fixed_bits = 0u;
    uint32_t best_blocked_index = (uint32_t)~0u;
    uint8_t best_blocked_priority = 0u;
    uint8_t best_blocked_fixed_bits = 0u;
    int have_best = 0;
    int have_blocked = 0;
    uint32_t bucket_index;
    bucket = arm_a32_td_bucket(word);
    if (bucket != 0) {
        bucket_index = (uint32_t)(bucket - asmkit_arm_a32_td_buckets);
        arm_consider_arm_a32_td_indexed_bucket(engine, word, decode_space, check_features, asmkit_arm_a32_td_records, &asmkit_arm_a32_td_bucket_subdescs[bucket_index], asmkit_arm_a32_td_bucket_indices, bucket->first, bucket->count, &best_record, &best_index, &best_priority, &best_fixed_bits, &have_best, &best_blocked_index, &best_blocked_priority, &best_blocked_fixed_bits, &have_blocked);
    }
    bucket = arm_a32_td_fallback_bucket(word);
    if (bucket != 0) {
        bucket_index = (uint32_t)(bucket - asmkit_arm_a32_td_fallback_buckets);
        arm_consider_arm_a32_td_indexed_bucket(engine, word, decode_space, check_features, asmkit_arm_a32_td_records, &asmkit_arm_a32_td_fallback_bucket_subdescs[bucket_index], asmkit_arm_a32_td_fallback_bucket_indices, bucket->first, bucket->count, &best_record, &best_index, &best_priority, &best_fixed_bits, &have_best, &best_blocked_index, &best_blocked_priority, &best_blocked_fixed_bits, &have_blocked);
    }
    arm_consider_arm_a32_td_indexed_bucket(engine, word, decode_space, check_features, asmkit_arm_a32_td_records, &asmkit_arm_a32_td_bucket_fallback2_subdesc, asmkit_arm_a32_td_bucket_fallback2_indices, 0u, ASMKIT_ARM_A32_TD_BUCKET_FALLBACK2_COUNT, &best_record, &best_index, &best_priority, &best_fixed_bits, &have_best, &best_blocked_index, &best_blocked_priority, &best_blocked_fixed_bits, &have_blocked);
    if (check_features && have_blocked && (!have_best || best_blocked_priority > best_priority || (best_blocked_priority == best_priority && best_blocked_fixed_bits > best_fixed_bits))) {
        return 0;
    }
    return best_record;
}

static const asmkit_arm_td_record_t* arm_find_a32_td_record(const asmkit_engine_t* engine, uint32_t word, int check_features)
{
    return arm_find_a32_td_record_in_space(engine, word, ASMKIT_ARM_TD_SPACE_ANY, check_features);
}

static const asmkit_arm_td_record_t* arm_find_thumb_td_record_in_space(const asmkit_engine_t* engine, uint32_t word, uint8_t size, uint8_t decode_space, int check_features)
{
    const asmkit_arm_td_record_t* best_record = 0;
    uint32_t best_index = (uint32_t)~0u;
    uint8_t best_priority = 0u;
    uint8_t best_fixed_bits = 0u;
    uint32_t best_blocked_index = (uint32_t)~0u;
    uint8_t best_blocked_priority = 0u;
    uint8_t best_blocked_fixed_bits = 0u;
    int have_best = 0;
    int have_blocked = 0;
    uint32_t bucket_index;
    if (size == 4u) {
        const asmkit_arm_thumb4_td_bucket_range_t* bucket = arm_thumb4_td_bucket(word);
        if (bucket != 0) {
            bucket_index = (uint32_t)(bucket - asmkit_arm_thumb4_td_buckets);
            arm_consider_arm_thumb4_td_indexed_bucket(engine, word, decode_space, check_features, asmkit_arm_thumb_td_records, &asmkit_arm_thumb4_td_bucket_subdescs[bucket_index], asmkit_arm_thumb4_td_bucket_indices, bucket->first, bucket->count, &best_record, &best_index, &best_priority, &best_fixed_bits, &have_best, &best_blocked_index, &best_blocked_priority, &best_blocked_fixed_bits, &have_blocked);
        }
        bucket = arm_thumb4_td_fallback_bucket(word);
        if (bucket != 0) {
            bucket_index = (uint32_t)(bucket - asmkit_arm_thumb4_td_fallback_buckets);
            arm_consider_arm_thumb4_td_indexed_bucket(engine, word, decode_space, check_features, asmkit_arm_thumb_td_records, &asmkit_arm_thumb4_td_fallback_bucket_subdescs[bucket_index], asmkit_arm_thumb4_td_fallback_bucket_indices, bucket->first, bucket->count, &best_record, &best_index, &best_priority, &best_fixed_bits, &have_best, &best_blocked_index, &best_blocked_priority, &best_blocked_fixed_bits, &have_blocked);
        }
        arm_consider_arm_thumb4_td_indexed_bucket(engine, word, decode_space, check_features, asmkit_arm_thumb_td_records, &asmkit_arm_thumb4_td_bucket_fallback2_subdesc, asmkit_arm_thumb4_td_bucket_fallback2_indices, 0u, ASMKIT_ARM_THUMB4_TD_BUCKET_FALLBACK2_COUNT, &best_record, &best_index, &best_priority, &best_fixed_bits, &have_best, &best_blocked_index, &best_blocked_priority, &best_blocked_fixed_bits, &have_blocked);
    } else {
        const asmkit_arm_thumb2_td_bucket_range_t* bucket = arm_thumb2_td_bucket(word);
        if (bucket != 0) {
            bucket_index = (uint32_t)(bucket - asmkit_arm_thumb2_td_buckets);
            arm_consider_arm_thumb2_td_indexed_bucket(engine, word, decode_space, check_features, asmkit_arm_thumb_td_records, &asmkit_arm_thumb2_td_bucket_subdescs[bucket_index], asmkit_arm_thumb2_td_bucket_indices, bucket->first, bucket->count, &best_record, &best_index, &best_priority, &best_fixed_bits, &have_best, &best_blocked_index, &best_blocked_priority, &best_blocked_fixed_bits, &have_blocked);
        }
        bucket = arm_thumb2_td_fallback_bucket(word);
        if (bucket != 0) {
            bucket_index = (uint32_t)(bucket - asmkit_arm_thumb2_td_fallback_buckets);
            arm_consider_arm_thumb2_td_indexed_bucket(engine, word, decode_space, check_features, asmkit_arm_thumb_td_records, &asmkit_arm_thumb2_td_fallback_bucket_subdescs[bucket_index], asmkit_arm_thumb2_td_fallback_bucket_indices, bucket->first, bucket->count, &best_record, &best_index, &best_priority, &best_fixed_bits, &have_best, &best_blocked_index, &best_blocked_priority, &best_blocked_fixed_bits, &have_blocked);
        }
        arm_consider_arm_thumb2_td_indexed_bucket(engine, word, decode_space, check_features, asmkit_arm_thumb_td_records, &asmkit_arm_thumb2_td_bucket_fallback2_subdesc, asmkit_arm_thumb2_td_bucket_fallback2_indices, 0u, ASMKIT_ARM_THUMB2_TD_BUCKET_FALLBACK2_COUNT, &best_record, &best_index, &best_priority, &best_fixed_bits, &have_best, &best_blocked_index, &best_blocked_priority, &best_blocked_fixed_bits, &have_blocked);
    }
    if (check_features && have_blocked && (!have_best || best_blocked_priority > best_priority || (best_blocked_priority == best_priority && best_blocked_fixed_bits > best_fixed_bits))) {
        return 0;
    }
    return best_record;
}

static const asmkit_arm_td_record_t* arm_find_thumb_td_record(const asmkit_engine_t* engine, uint32_t word, uint8_t size, int check_features)
{
    return arm_find_thumb_td_record_in_space(engine, word, size, ASMKIT_ARM_TD_SPACE_PRIMARY, check_features);
}

static asmkit_status_t arm_finish(
    const asmkit_engine_t* engine,
    const uint8_t* code,
    uint64_t address,
    asmkit_inst_t* out_inst,
    uint32_t size,
    uint32_t id,
    asmkit_inst_class_t inst_class,
    uint32_t flags)
{
    asmkit_zero(out_inst, sizeof(*out_inst));
    out_inst->arch = ASMKIT_ARCH_ARM;
    out_inst->mode = engine->config.mode;
    out_inst->id = id;
    out_inst->mnemonic_id = arm_mnemonic_id(id);
    out_inst->inst_class = inst_class;
    out_inst->address = address;
    out_inst->size = size;
    out_inst->flags = flags;
    if (engine->config.mode == ASMKIT_MODE_ARM_A32 && size == 4u && (asmkit_load32le(code) >> 28u) < 0x0eu) {
        out_inst->flags |= ASMKIT_INST_FLAG_CONDITIONAL;
    }
    asmkit_copy(out_inst->bytes, code, size > ASMKIT_MAX_INST_BYTES ? ASMKIT_MAX_INST_BYTES : size);
    return ASMKIT_OK;
}

static asmkit_status_t arm_finish_td(
    const asmkit_engine_t* engine,
    const uint8_t* code,
    uint64_t address,
    asmkit_inst_t* out_inst,
    uint32_t word,
    const asmkit_arm_td_record_t* record)
{
    asmkit_zero(out_inst, sizeof(*out_inst));
    out_inst->arch = ASMKIT_ARCH_ARM;
    out_inst->mode = engine->config.mode;
    out_inst->id = record->id;
    out_inst->mnemonic_id = record->mnemonic_id;
    out_inst->inst_class = record->inst_class;
    out_inst->address = address;
    out_inst->size = record->size;
    out_inst->flags = record->flags;
    if (engine->config.mode == ASMKIT_MODE_ARM_A32 && record->size == 4u && (word >> 28u) < 0x0eu) {
        out_inst->flags |= ASMKIT_INST_FLAG_CONDITIONAL;
    }
    asmkit_copy(out_inst->bytes, code, record->size > ASMKIT_MAX_INST_BYTES ? ASMKIT_MAX_INST_BYTES : record->size);
    if (!arm_decode_td_operands(record, word, address, out_inst)) {
        return ASMKIT_ERR_DECODE_FAILED;
    }
    if (record->id == ASMKIT_ARM_TDINST_t2IT && out_inst->operand_count >= 1u && out_inst->operands[0].kind == ASMKIT_OP_IMM && out_inst->operands[0].imm == 15) {
        out_inst->operands[0].imm = 14;
    }
    return ASMKIT_OK;
}

static void arm_add_pc_operand(asmkit_inst_t* inst, int64_t disp, uint64_t target, uint8_t width)
{
    uint8_t index;
    if (inst->operand_count >= ASMKIT_MAX_OPERANDS) {
        return;
    }
    index = inst->operand_count++;
    inst->operands[index].kind = ASMKIT_OP_PC_REL;
    inst->operands[index].imm = disp;
    inst->operands[index].abs_target = target;
    inst->operands[index].width = width;
    inst->operands[index].operand_index = index;
    inst->operands[index].flags = ASMKIT_OPERAND_FLAG_EXPLICIT | ASMKIT_OPERAND_FLAG_READ | ASMKIT_OPERAND_FLAG_RELATIVE | ASMKIT_OPERAND_FLAG_SIGNED;
}

static int arm_append_gpr_operand(asmkit_inst_t* inst, uint32_t encoded_reg, uint32_t flags)
{
    uint8_t index;
    uint32_t reg = arm_td_reg_id(encoded_reg & 0x0fu, 32u, ASMKIT_ARM_REGCLASS_GPR);
    if (reg == ASMKIT_ARM_REG_INVALID) {
        return 0;
    }
    if (inst->operand_count >= ASMKIT_MAX_OPERANDS) {
        return 0;
    }
    index = inst->operand_count++;
    inst->operands[index] = asmkit_operand_reg(reg, 32u);
    inst->operands[index].operand_index = index;
    inst->operands[index].flags |= ASMKIT_OPERAND_FLAG_EXPLICIT | flags;
    return 1;
}

static int arm_add_gpr_operand(asmkit_inst_t* inst, uint32_t encoded_reg)
{
    inst->operand_count = 0u;
    return arm_append_gpr_operand(inst, encoded_reg, ASMKIT_OPERAND_FLAG_READ);
}

static asmkit_status_t arm_decode_thumb_shared_a32_space(
    const asmkit_engine_t* engine,
    const uint8_t* code,
    uint64_t address,
    asmkit_inst_t* out_inst,
    uint32_t shared_word,
    uint8_t decode_space,
    int* matched)
{
    const asmkit_arm_td_record_t* td_record;
    *matched = 0;
    td_record = arm_find_a32_td_record_in_space(engine, shared_word, decode_space, 1);
    if (td_record != 0) {
        *matched = 1;
        return arm_finish_td(engine, code, address, out_inst, shared_word, td_record);
    }
    if (arm_find_a32_td_record_in_space(engine, shared_word, decode_space, 0) != 0) {
        *matched = 1;
        return ASMKIT_ERR_UNSUPPORTED_FEATURE;
    }
    return ASMKIT_ERR_DECODE_FAILED;
}

static asmkit_status_t arm_decode_a32(const asmkit_engine_t* engine, const uint8_t* code, size_t code_size, uint64_t address, asmkit_inst_t* out_inst)
{
    const asmkit_arm_td_record_t* td_record;
    uint32_t w;
    int64_t disp;

    if (code_size < 4u) {
        return ASMKIT_ERR_DECODE_FAILED;
    }
    w = asmkit_load32le(code);
    if ((w >> 28u) != 0x0fu && (w & 0x0e000000u) == 0x0a000000u) {
        disp = arm_sign_extend(w & 0x00ffffffu, 24u) << 2;
        disp += 8;
        (void)arm_finish(engine, code, address, out_inst, 4u,
            (w & 0x01000000u) != 0u ? ASMKIT_ARM_BL : ASMKIT_ARM_B,
            (w & 0x01000000u) != 0u ? ASMKIT_INST_DIRECT_CALL : ASMKIT_INST_DIRECT_BRANCH,
            ASMKIT_INST_FLAG_PC_RELATIVE | ASMKIT_INST_FLAG_DIRECT | (((w & 0x01000000u) != 0u) ? ASMKIT_INST_FLAG_CALL : ASMKIT_INST_FLAG_TERMINATOR));
        arm_add_pc_operand(out_inst, disp, address + (uint64_t)disp, 24u);
        return ASMKIT_OK;
    }
    if ((w & 0x0ffffff0u) == 0x012fff10u) {
        (void)arm_finish(engine, code, address, out_inst, 4u, ASMKIT_ARM_BX, ASMKIT_INST_INDIRECT_BRANCH,
            ASMKIT_INST_FLAG_TERMINATOR | ASMKIT_INST_FLAG_STATE_SWITCH);
        return arm_add_gpr_operand(out_inst, w & 0x0fu) ? ASMKIT_OK : ASMKIT_ERR_DECODE_FAILED;
    }
    if ((w & 0x0ffffff0u) == 0x012fff30u) {
        (void)arm_finish(engine, code, address, out_inst, 4u, ASMKIT_ARM_BLX, ASMKIT_INST_INDIRECT_CALL,
            ASMKIT_INST_FLAG_CALL | ASMKIT_INST_FLAG_STATE_SWITCH);
        return arm_add_gpr_operand(out_inst, w & 0x0fu) ? ASMKIT_OK : ASMKIT_ERR_DECODE_FAILED;
    }
    if ((w & 0x0f7f0000u) == 0x051f0000u) {
        disp = (int64_t)(w & 0x00000fffu);
        if ((w & 0x00800000u) == 0u) {
            disp = -disp;
        }
        disp += 8;
        (void)arm_finish(engine, code, address, out_inst, 4u, ASMKIT_ARM_LDR_LITERAL, ASMKIT_INST_LOAD,
            ASMKIT_INST_FLAG_PC_RELATIVE | ASMKIT_INST_FLAG_LITERAL);
        if (!arm_append_gpr_operand(out_inst, (w >> 12u) & 0x0fu, ASMKIT_OPERAND_FLAG_WRITE)) {
            return ASMKIT_ERR_DECODE_FAILED;
        }
        arm_add_pc_operand(out_inst, disp, address + (uint64_t)disp, 12u);
        return ASMKIT_OK;
    }
    td_record = arm_find_a32_td_record(engine, w, 1);
    if (td_record != 0) {
        return arm_finish_td(engine, code, address, out_inst, w, td_record);
    }
    if (arm_find_a32_td_record(engine, w, 0) != 0) {
        return ASMKIT_ERR_UNSUPPORTED_FEATURE;
    }
    return arm_finish(engine, code, address, out_inst, 4u, ASMKIT_ARM_OTHER, ASMKIT_INST_OTHER, 0u);
}

static asmkit_status_t arm_decode_thumb(const asmkit_engine_t* engine, const uint8_t* code, size_t code_size, uint64_t address, asmkit_inst_t* out_inst)
{
    const asmkit_arm_td_record_t* td_record;
    uint32_t w;
    uint32_t shared_w;
    uint32_t cond;
    uint16_t h1;
    uint16_t h2;
    int64_t disp;
    asmkit_status_t shared_status;
    int shared_matched;

    if (code_size < 2u) {
        return ASMKIT_ERR_DECODE_FAILED;
    }
    h1 = asmkit_load16le(code);
    if ((h1 & 0xff00u) == 0xbf00u && (h1 & 0x000fu) != 0u) {
        (void)arm_finish(engine, code, address, out_inst, 2u, ASMKIT_THUMB_IT, ASMKIT_INST_ARM_IT, 0u);
        out_inst->operand_count = 2u;
        out_inst->operands[0] = asmkit_operand_imm((int64_t)((((h1 >> 4u) & 0x0fu) == 0x0fu) ? 0x0eu : ((h1 >> 4u) & 0x0fu)), 4u);
        out_inst->operands[0].operand_index = 0u;
        out_inst->operands[1] = asmkit_operand_imm((int64_t)(h1 & 0x0fu), 4u);
        out_inst->operands[1].operand_index = 1u;
        return ASMKIT_OK;
    }
    if ((h1 & 0xf800u) == 0xe000u) {
        disp = arm_sign_extend(h1 & 0x07ffu, 11u) << 1;
        disp += 4;
        (void)arm_finish(engine, code, address, out_inst, 2u, ASMKIT_THUMB_B, ASMKIT_INST_DIRECT_BRANCH,
            ASMKIT_INST_FLAG_PC_RELATIVE | ASMKIT_INST_FLAG_DIRECT | ASMKIT_INST_FLAG_TERMINATOR);
        arm_add_pc_operand(out_inst, disp, address + (uint64_t)disp, 11u);
        return ASMKIT_OK;
    }
    cond = (uint32_t)((h1 >> 8u) & 0x0fu);
    if ((h1 & 0xf000u) == 0xd000u && cond < 0x0eu) {
        disp = arm_sign_extend(h1 & 0x00ffu, 8u) << 1;
        disp += 4;
        (void)arm_finish(engine, code, address, out_inst, 2u, ASMKIT_THUMB_B_COND, ASMKIT_INST_COND_BRANCH,
            ASMKIT_INST_FLAG_PC_RELATIVE | ASMKIT_INST_FLAG_DIRECT | ASMKIT_INST_FLAG_CONDITIONAL);
        arm_add_pc_operand(out_inst, disp, address + (uint64_t)disp, 8u);
        return ASMKIT_OK;
    }
    if ((h1 & 0xff80u) == 0x4700u) {
        (void)arm_finish(engine, code, address, out_inst, 2u, ASMKIT_THUMB_BX, ASMKIT_INST_INDIRECT_BRANCH,
            ASMKIT_INST_FLAG_TERMINATOR | ASMKIT_INST_FLAG_STATE_SWITCH);
        return arm_add_gpr_operand(out_inst, (uint32_t)((h1 >> 3u) & 0x0fu)) ? ASMKIT_OK : ASMKIT_ERR_DECODE_FAILED;
    }
    if ((h1 & 0xff80u) == 0x4780u) {
        (void)arm_finish(engine, code, address, out_inst, 2u, ASMKIT_THUMB_BLX, ASMKIT_INST_INDIRECT_CALL,
            ASMKIT_INST_FLAG_CALL | ASMKIT_INST_FLAG_STATE_SWITCH);
        return arm_add_gpr_operand(out_inst, (uint32_t)((h1 >> 3u) & 0x0fu)) ? ASMKIT_OK : ASMKIT_ERR_DECODE_FAILED;
    }
    if ((h1 & 0xf800u) >= 0xe800u) {
        if (code_size < 4u) {
            return ASMKIT_ERR_DECODE_FAILED;
        }
        h2 = asmkit_load16le(code + 2);
        if ((h1 & 0xf800u) == 0xf000u && (h2 & 0xd000u) == 0xd000u) {
            uint32_t s_bit;
            uint32_t j1_bit;
            uint32_t j2_bit;
            uint32_t i1_bit;
            uint32_t i2_bit;
            uint32_t imm_value;
            s_bit = (uint32_t)((h1 >> 10u) & 1u);
            j1_bit = (uint32_t)((h2 >> 13u) & 1u);
            j2_bit = (uint32_t)((h2 >> 11u) & 1u);
            i1_bit = (uint32_t)(1u ^ (j1_bit ^ s_bit));
            i2_bit = (uint32_t)(1u ^ (j2_bit ^ s_bit));
            imm_value = (s_bit << 24u) | (i1_bit << 23u) | (i2_bit << 22u) | ((uint32_t)(h1 & 0x03ffu) << 12u) | ((uint32_t)(h2 & 0x07ffu) << 1u);
            disp = arm_sign_extend(imm_value, 25u) + 4;
            (void)arm_finish(engine, code, address, out_inst, 4u, ASMKIT_THUMB_BL, ASMKIT_INST_DIRECT_CALL,
                ASMKIT_INST_FLAG_PC_RELATIVE | ASMKIT_INST_FLAG_DIRECT | ASMKIT_INST_FLAG_CALL);
            arm_add_pc_operand(out_inst, disp, address + (uint64_t)disp, 24u);
            return ASMKIT_OK;
        }
        w = ((uint32_t)h1 << 16) | (uint32_t)h2;
        td_record = arm_find_thumb_td_record(engine, w, 4u, 1);
        if (td_record != 0) {
            return arm_finish_td(engine, code, address, out_inst, w, td_record);
        }
        if (arm_find_thumb_td_record(engine, w, 4u, 0) != 0) {
            return ASMKIT_ERR_UNSUPPORTED_FEATURE;
        }
        if ((w >> 28u) == 0x0eu) {
            shared_status = arm_decode_thumb_shared_a32_space(engine, code, address, out_inst, w, ASMKIT_ARM_TD_SPACE_VFP, &shared_matched);
            if (shared_matched) {
                return shared_status;
            }
        }
        shared_status = arm_decode_thumb_shared_a32_space(engine, code, address, out_inst, w, ASMKIT_ARM_TD_SPACE_VFPV8, &shared_matched);
        if (shared_matched) {
            return shared_status;
        }
        if ((w >> 28u) == 0x0eu) {
            shared_status = arm_decode_thumb_shared_a32_space(engine, code, address, out_inst, w, ASMKIT_ARM_TD_SPACE_NEON_DUP, &shared_matched);
            if (shared_matched) {
                return shared_status;
            }
        }
        if ((w >> 24u) == 0x0f9u) {
            shared_w = (w & UINT32_C(0xf0ffffff)) | UINT32_C(0x04000000);
            shared_status = arm_decode_thumb_shared_a32_space(engine, code, address, out_inst, shared_w, ASMKIT_ARM_TD_SPACE_NEON_LOAD_STORE, &shared_matched);
            if (shared_matched) {
                return shared_status;
            }
        }
        if (((w >> 24u) & 0x0fu) == 0x0fu) {
            shared_w = (w & UINT32_C(0xf0ffffff)) | ((w & UINT32_C(0x10000000)) >> 4u) | UINT32_C(0x12000000);
            shared_status = arm_decode_thumb_shared_a32_space(engine, code, address, out_inst, shared_w, ASMKIT_ARM_TD_SPACE_NEON_DATA, &shared_matched);
            if (shared_matched) {
                return shared_status;
            }
            shared_status = arm_decode_thumb_shared_a32_space(engine, code, address, out_inst, shared_w, ASMKIT_ARM_TD_SPACE_V8_CRYPTO, &shared_matched);
            if (shared_matched) {
                return shared_status;
            }
            shared_w = w & UINT32_C(0xf3ffffff);
            shared_status = arm_decode_thumb_shared_a32_space(engine, code, address, out_inst, shared_w, ASMKIT_ARM_TD_SPACE_V8_NEON, &shared_matched);
            if (shared_matched) {
                return shared_status;
            }
        }
        td_record = arm_find_thumb_td_record_in_space(engine, w, 4u, ASMKIT_ARM_TD_SPACE_THUMB2_COPROC, 1);
        if (td_record != 0) {
            return arm_finish_td(engine, code, address, out_inst, w, td_record);
        }
        if (arm_find_thumb_td_record_in_space(engine, w, 4u, ASMKIT_ARM_TD_SPACE_THUMB2_COPROC, 0) != 0) {
            return ASMKIT_ERR_UNSUPPORTED_FEATURE;
        }
        td_record = arm_find_thumb_td_record_in_space(engine, w, 4u, ASMKIT_ARM_TD_SPACE_THUMB2_CDE, 1);
        if (td_record != 0) {
            return arm_finish_td(engine, code, address, out_inst, w, td_record);
        }
        if (arm_find_thumb_td_record_in_space(engine, w, 4u, ASMKIT_ARM_TD_SPACE_THUMB2_CDE, 0) != 0) {
            return ASMKIT_ERR_UNSUPPORTED_FEATURE;
        }
        return arm_finish(engine, code, address, out_inst, 4u, ASMKIT_ARM_OTHER, ASMKIT_INST_OTHER, 0u);
    }
    td_record = arm_find_thumb_td_record(engine, (uint32_t)h1, 2u, 1);
    if (td_record != 0) {
        return arm_finish_td(engine, code, address, out_inst, (uint32_t)h1, td_record);
    }
    if (arm_find_thumb_td_record(engine, (uint32_t)h1, 2u, 0) != 0) {
        return ASMKIT_ERR_UNSUPPORTED_FEATURE;
    }
    return arm_finish(engine, code, address, out_inst, 2u, ASMKIT_ARM_OTHER, ASMKIT_INST_OTHER, 0u);
}

asmkit_status_t asmkit_gen_arm_decode_one(const asmkit_engine_t* engine, const uint8_t* code, size_t code_size, uint64_t address, asmkit_inst_t* out_inst)
{
    if (engine == 0 || code == 0 || out_inst == 0) {
        return ASMKIT_ERR_INVALID_ARGUMENT;
    }
    if (engine->config.mode == ASMKIT_MODE_ARM_A32) {
        return arm_decode_a32(engine, code, code_size, address, out_inst);
    }
    if (engine->config.mode == ASMKIT_MODE_ARM_THUMB) {
        return arm_decode_thumb(engine, code, code_size, address, out_inst);
    }
    return ASMKIT_ERR_UNSUPPORTED_MODE;
}
